MRFShrinkeageCmd::MRFShrinkeageCmd() :
CATStateCommand ("MRFShrinkeageCmd", CATDlgEngOneShot, CATCommandModeShared)
//  Valid states are CATDlgEngOneShot and CATDlgEngRepeat
, _pApplicationFrame(NULL)
, _pEditor(NULL)
, _pHSO(NULL)
, _pISO(NULL)
, _spMechanicalPart(NULL_var)
, _spGSMFactory(NULL_var)
, _pRefSurfaceDialogAgent(NULL)
, _pRefSurfacePathElementAgent(NULL)
, _pRefSurfacePathElement(NULL)
, _spRefSurface(NULL_var)
, _pSegmentDialogAgent(NULL)
, _pSegmentPathElementAgent(NULL)
, _pSegmentPathElement(NULL)
, _spSegment(NULL_var)
, _pVentGeomSetDialogAgent(NULL)
, _pVentGeomSetPathElementAgent(NULL)
, _pVentGeomSetPathElement(NULL)
, _spVentGeomSet(NULL_var)
, _pSipeSetDialogAgent(NULL)
, _pSipeSetPathElementAgent(NULL)
, _pSipeSetPathElement(NULL)
, _spSipeSet(NULL_var)
, _pMRFShrinkeageDlg(NULL)
, _spShrinkeageFactor(NULL_var)
{
	_pApplicationFrame = CATApplicationFrame::GetFrame();
	_pEditor = CATFrmEditor::GetCurrentEditor();
	if (NULL != _pEditor)
	{
		_pHSO = _pEditor->GetHSO();
		_pISO = _pEditor->GetISO();

		CATPathElement  oActivePath = _pEditor->GetUIActiveObject();
		oActivePath.InitToLeafElement();
		CATBaseUnknown_var spCBUOnCurrObject = oActivePath.NextFatherElement();

		if (NULL_var != spCBUOnCurrObject)
		{
			CATIMmiUsePrtPart * piPrtPart = NULL;
			spCBUOnCurrObject->QueryInterface(IID_CATIMmiUsePrtPart, (void**)&piPrtPart);
			if (NULL != piPrtPart)
			{
				_spMechanicalPart = piPrtPart;
				if (NULL_var != _spMechanicalPart)
				{
					CATIMmiPrtContainer_var spPrtCont;
					_spMechanicalPart->GetPrtContainer(spPrtCont);
					if (NULL_var != spPrtCont)
					{
						_spGSMFactory = spPrtCont;
					}
				}
				piPrtPart->Release();  piPrtPart = NULL;
			}
		}
	}

	_pMRFShrinkeageDlg = new MRFShrinkeageDlg();
}

