MRFShrinkeageCmd::~MRFShrinkeageCmd()
{
	if (_pMRFShrinkeageDlg != NULL)
		_pMRFShrinkeageDlg->RequestDelayedDestruction();
		_pMRFShrinkeageDlg = NULL;

	if (NULL != _pHSO && !_pHSO->IsNull())
	{
		_pHSO->Empty();
		_pHSO = NULL;
	}

	if (NULL != _pISO && !_pISO->IsNull())
	{
		_pISO->Empty();
		_pISO = NULL;
	}

	if (_pEditor != NULL)
		_pEditor = NULL;

	if (_pApplicationFrame != NULL)
		_pApplicationFrame = NULL;

	if (NULL_var != _spMechanicalPart)
		_spMechanicalPart = NULL_var;

	if (NULL_var != _spGSMFactory)
		_spGSMFactory = NULL_var;

	if (_pRefSurfaceDialogAgent)
		_pRefSurfaceDialogAgent->RequestDelayedDestruction(); _pRefSurfaceDialogAgent = NULL;

	if (_pRefSurfacePathElementAgent)
		_pRefSurfacePathElementAgent->RequestDelayedDestruction(); _pRefSurfacePathElementAgent = NULL;

	if (_pRefSurfacePathElement)
		_pRefSurfacePathElement = NULL;

	_spRefSurface = NULL_var;

	if (_pSegmentDialogAgent)
		_pSegmentDialogAgent->RequestDelayedDestruction(); _pSegmentDialogAgent = NULL;

	if (_pSegmentPathElementAgent)
		_pSegmentPathElementAgent->RequestDelayedDestruction(); _pSegmentPathElementAgent = NULL;

	if (_pSegmentPathElement)
		_pSegmentPathElement = NULL;

	_spSegment = NULL_var;

	if (_pVentGeomSetDialogAgent)
		_pVentGeomSetDialogAgent->RequestDelayedDestruction(); _pVentGeomSetDialogAgent = NULL;

	if (_pVentGeomSetPathElementAgent)
		_pVentGeomSetPathElementAgent->RequestDelayedDestruction(); _pVentGeomSetPathElementAgent = NULL;

	if (_pVentGeomSetPathElement)
		_pVentGeomSetPathElement = NULL;

	_spVentGeomSet = NULL_var;

	if (_pSipeSetDialogAgent)
		_pSipeSetDialogAgent->RequestDelayedDestruction(); _pSipeSetDialogAgent = NULL;
	
	if (_pSipeSetPathElementAgent)
		_pSipeSetPathElementAgent->RequestDelayedDestruction(); _pSipeSetPathElementAgent = NULL;

	if (_pSipeSetPathElement)
		_pSipeSetPathElement = NULL;

	_spSipeSet = NULL_var;

	_spShrinkeageFactor = NULL_var;
}


//-------------------------------------------------------------------------
// BuildGraph()
//-------------------------------------------------------------------------
void MRFShrinkeageCmd::BuildGraph()
{
	if (NULL != _pMRFShrinkeageDlg)
	{
		AddAnalyseNotificationCB(_pMRFShrinkeageDlg, _pMRFShrinkeageDlg->GetDiaOKNotification(), (CATCommandMethod)& MRFShrinkeageCmd::ActionOne, NULL);
		AddAnalyseNotificationCB(_pMRFShrinkeageDlg, _pMRFShrinkeageDlg->GetDiaCANCELNotification(), (CATCommandMethod)& MRFShrinkeageCmd::ActionClose, NULL);
		AddAnalyseNotificationCB(_pMRFShrinkeageDlg, _pMRFShrinkeageDlg->GetWindCloseNotification(), (CATCommandMethod)& MRFShrinkeageCmd::ActionClose, NULL);

		CATListOfCATString List3DElements;
		List3DElements.Append("CATI3DGeometricalElement");

		_pRefSurfacePathElementAgent = new CATPathElementAgent("RefSurfacePathElementAgent");
		if (_pRefSurfacePathElementAgent)
		{
			_pRefSurfacePathElementAgent->SetOrderedTypeList(List3DElements);
			_pRefSurfacePathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

		}
		_pRefSurfaceDialogAgent = new CATDialogAgent("RefSurfaceDialogAgent");
		if (_pRefSurfaceDialogAgent)
		{
			CATDlgSelectorList* pRefSurfSelector = _pMRFShrinkeageDlg->GetRefSurfaceSelector();
			if (NULL != pRefSurfSelector)
			{
				_pRefSurfaceDialogAgent->AcceptOnNotify(pRefSurfSelector, pRefSurfSelector->GetListSelectNotification());
			}
		}

		_pSegmentPathElementAgent = new CATPathElementAgent("SegmentPathElementAgent");
		if (_pSegmentPathElementAgent)
		{
			_pSegmentPathElementAgent->SetOrderedTypeList(List3DElements);
			_pSegmentPathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

		}
		_pSegmentDialogAgent = new CATDialogAgent("SegmentDialogAgent");
		if (_pSegmentDialogAgent)
		{
			CATDlgSelectorList* pSegmentSelector = _pMRFShrinkeageDlg->GetSegmentSelector();
			if (NULL != pSegmentSelector)
			{
				_pSegmentDialogAgent->AcceptOnNotify(pSegmentSelector, pSegmentSelector->GetListSelectNotification());
			}
		}

		_pVentGeomSetPathElementAgent = new CATPathElementAgent("VentGeomSetPathElementAgent");
		if (_pVentGeomSetPathElementAgent)
		{
			_pVentGeomSetPathElementAgent->AddOrderedElementType("CATIBodyRequest");
			_pVentGeomSetPathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

		}
		_pVentGeomSetDialogAgent = new CATDialogAgent("VentGeomSetDialogAgent");
		if (_pVentGeomSetDialogAgent)
		{
			CATDlgSelectorList* pVentSetSelector = _pMRFShrinkeageDlg->GetVentGeomSetSelector();
			if (NULL != pVentSetSelector)
			{
				_pVentGeomSetDialogAgent->AcceptOnNotify(pVentSetSelector, pVentSetSelector->GetListSelectNotification());
			}
		}

		_pSipeSetPathElementAgent = new CATPathElementAgent("SipeSetPathElementAgent");
		if (_pSipeSetPathElementAgent)
		{
			_pSipeSetPathElementAgent->AddOrderedElementType("CATIBodyRequest");
			_pSipeSetPathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

		}
		_pSipeSetDialogAgent = new CATDialogAgent("SipeSetDialogAgent");
		if (_pSipeSetDialogAgent)
		{
			CATDlgSelectorList* pSipeSetSelector = _pMRFShrinkeageDlg->GetSipeGeomSetSelector();
			if (NULL != pSipeSetSelector)
			{
				_pSipeSetDialogAgent->AcceptOnNotify(pSipeSetSelector, pSipeSetSelector->GetListSelectNotification());
			}
		}

		CATDialogState * pRefSurfaceState = GetInitialState("RefSurfaceState");
		CATDialogState * pSegmentState = AddDialogState("SegmentState");
		CATDialogState * pVentSetState = AddDialogState("VentSetState");
		CATDialogState * pSipeSetState = AddDialogState("SipeSetState");

		if (NULL != pRefSurfaceState && NULL != pSegmentState && NULL != pVentSetState && NULL != pSipeSetState)
		{
			pRefSurfaceState->AddDialogAgent(_pRefSurfaceDialogAgent);
			pRefSurfaceState->AddDialogAgent(_pSegmentDialogAgent);
			pRefSurfaceState->AddDialogAgent(_pVentGeomSetDialogAgent);
			pRefSurfaceState->AddDialogAgent(_pSipeSetDialogAgent);
			pRefSurfaceState->AddDialogAgent(_pRefSurfacePathElementAgent);

			pSegmentState->AddDialogAgent(_pRefSurfaceDialogAgent);
			pSegmentState->AddDialogAgent(_pSegmentDialogAgent);
			pSegmentState->AddDialogAgent(_pVentGeomSetDialogAgent);
			pSegmentState->AddDialogAgent(_pSipeSetDialogAgent);
			pSegmentState->AddDialogAgent(_pSegmentPathElementAgent);
			pSegmentState->AddDialogAgent(_pRefSurfacePathElementAgent);

			pVentSetState->AddDialogAgent(_pRefSurfaceDialogAgent);
			pVentSetState->AddDialogAgent(_pSegmentDialogAgent);
			pVentSetState->AddDialogAgent(_pVentGeomSetDialogAgent);
			pVentSetState->AddDialogAgent(_pSipeSetDialogAgent);
			pVentSetState->AddDialogAgent(_pVentGeomSetPathElementAgent);
			pVentSetState->AddDialogAgent(_pSegmentPathElementAgent);
			pVentSetState->AddDialogAgent(_pSipeSetPathElementAgent);

			pSipeSetState->AddDialogAgent(_pRefSurfaceDialogAgent);
			pSipeSetState->AddDialogAgent(_pSegmentDialogAgent);
			pSipeSetState->AddDialogAgent(_pVentGeomSetDialogAgent);
			pSipeSetState->AddDialogAgent(_pSipeSetDialogAgent);
			pSipeSetState->AddDialogAgent(_pSipeSetPathElementAgent);
			pSipeSetState->AddDialogAgent(_pVentGeomSetPathElementAgent);

			CATCommandClientData RefSurfaceData("RefSurface");
			CATCommandClientData SegmentData("Segment");
			CATCommandClientData VentSetData("VentSet");
			CATCommandClientData SipeSetData("SipeSet");

			AddTransition(pRefSurfaceState, pRefSurfaceState, IsOutputSetCondition(_pRefSurfaceDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, RefSurfaceData));
			AddTransition(pSegmentState, pRefSurfaceState, IsOutputSetCondition(_pRefSurfaceDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, RefSurfaceData));
			AddTransition(pVentSetState, pRefSurfaceState, IsOutputSetCondition(_pRefSurfaceDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, RefSurfaceData));
			AddTransition(pSipeSetState, pRefSurfaceState, IsOutputSetCondition(_pRefSurfaceDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, RefSurfaceData));

			AddTransition(pRefSurfaceState, pSegmentState, IsOutputSetCondition(_pSegmentDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, SegmentData));
			AddTransition(pSegmentState, pSegmentState, IsOutputSetCondition(_pSegmentDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, SegmentData));
			AddTransition(pVentSetState, pSegmentState, IsOutputSetCondition(_pSegmentDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, SegmentData));
			AddTransition(pSipeSetState, pSegmentState, IsOutputSetCondition(_pSegmentDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, SegmentData));

			AddTransition(pRefSurfaceState, pVentSetState, IsOutputSetCondition(_pVentGeomSetDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, VentSetData));
			AddTransition(pSegmentState, pVentSetState, IsOutputSetCondition(_pVentGeomSetDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, VentSetData));
			AddTransition(pVentSetState, pVentSetState, IsOutputSetCondition(_pVentGeomSetDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, VentSetData));
			AddTransition(pSipeSetState, pVentSetState, IsOutputSetCondition(_pVentGeomSetDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, VentSetData));

			AddTransition(pRefSurfaceState, pSipeSetState, IsOutputSetCondition(_pSipeSetDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, SipeSetData));
			AddTransition(pSegmentState, pSipeSetState, IsOutputSetCondition(_pSipeSetDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, SipeSetData));
			AddTransition(pVentSetState, pSipeSetState, IsOutputSetCondition(_pSipeSetDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, SipeSetData));
			AddTransition(pSipeSetState, pSipeSetState, IsOutputSetCondition(_pSipeSetDialogAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnSelectorListSelected, NULL, NULL, SipeSetData));

			AddTransition(pRefSurfaceState, pSegmentState, IsOutputSetCondition(_pRefSurfacePathElementAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnObjectSelection, NULL, NULL, RefSurfaceData));
			AddTransition(pSegmentState, pVentSetState, IsOutputSetCondition(_pSegmentPathElementAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnObjectSelection, NULL, NULL, SegmentData));
			AddTransition(pVentSetState, pSipeSetState, IsOutputSetCondition(_pVentGeomSetPathElementAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnObjectSelection, NULL, NULL, VentSetData));
			AddTransition(pSipeSetState, pSipeSetState, IsOutputSetCondition(_pSipeSetPathElementAgent), Action((ActionMethod)&MRFShrinkeageCmd::OnObjectSelection, NULL, NULL, SipeSetData));

			CATDlgContextualMenu* pSufaceCtxMenu = _pMRFShrinkeageDlg->GetRefSurfCtxMenu();
			if (NULL != pSufaceCtxMenu)
			{
				AddAnalyseNotificationCB(pSufaceCtxMenu, pSufaceCtxMenu->GetVisibilityNotification(), (CATCommandMethod)&MRFShrinkeageCmd::OnCtxMenu, RefSurfaceData);
			}

			CATDlgContextualMenu* pSegmentCtxMenu = _pMRFShrinkeageDlg->GetSegmentCtxMenu();
			if (NULL != pSegmentCtxMenu)
			{
				AddAnalyseNotificationCB(pSegmentCtxMenu, pSegmentCtxMenu->GetVisibilityNotification(), (CATCommandMethod)&MRFShrinkeageCmd::OnCtxMenu, SegmentData);
			}

			CATDlgContextualMenu* pVentSetCtxMenu = _pMRFShrinkeageDlg->GetVentSetCtxMenu();
			if (NULL != pVentSetCtxMenu)
			{
				AddAnalyseNotificationCB(pVentSetCtxMenu, pVentSetCtxMenu->GetVisibilityNotification(), (CATCommandMethod)&MRFShrinkeageCmd::OnCtxMenu, VentSetData);
			}

			CATDlgContextualMenu* pSipeSetCtxMenu = _pMRFShrinkeageDlg->GetSipeSetCtxMenu();
			if (NULL != pSipeSetCtxMenu)
			{
				AddAnalyseNotificationCB(pSipeSetCtxMenu, pSipeSetCtxMenu->GetVisibilityNotification(), (CATCommandMethod)&MRFShrinkeageCmd::OnCtxMenu, SipeSetData);
			}
		}
	}
}


//-------------------------------------------------------------------------
// ActionOne ()
//-------------------------------------------------------------------------
void MRFShrinkeageCmd::ActionOne(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	CATBoolean bAction = CATFalse;
	CATDlgSpinner * pShrnkSpinner = _pMRFShrinkeageDlg->GetShrinkeageFactor();
	if (NULL != pShrnkSpinner)
	{
		double pShrinkeageFactor = pShrnkSpinner->GetValue();

		int SegmentIndex = GetSegmentIndex();
		_strSegmentIndex.BuildFromNum(SegmentIndex);

		if (NULL_var == _spOGSShrinkageSet)
		{
			GetOrCreateShrinkeageSet();
		}
		_spShrinkeageFactor = NULL_var;

		if (NULL_var != _spOGSShrinkageSet && NULL_var == _spShrinkeageFactor)
		{
			bAction = GetORCreateShrinkeageParam(pShrinkeageFactor);
		}

		if (bAction && pShrinkeageFactor > 0. && pShrinkeageFactor < 1.)
		{
			if (NULL_var != _spRefSurface)
			{
				bAction = CreateTargetSurface(pShrinkeageFactor);

				if (bAction && NULL_var != _spTargetSurface && NULL_var != _spSegment)
				{
					//bAction = ValidateWrapInputs();
					//if (bAction)
						bAction = CreateSegmentShrinkeage();
				}
				if (bAction && NULL_var != _spVentGeomSet)
				{
					GetListOfVents(_spListOfVents);
					if (_spListOfVents.Size() > 0)
					{
						ExtractVentLines(_spListOfVents, _spListOfVentLines);
						if (_spListOfVentLines.Size() > 0)
						{
							AssemblePlanes(_spListOfVentLines, _spVentLineAssembled);
							if (NULL_var != _spOGSShrinkageSet && NULL_var != _spVentLineAssembled)
							{
								CATIAlias_var spAlias = _spVentLineAssembled;
								if (NULL_var != spAlias)
								{
									CATUnicodeString strName = "VentsAssembled_";
									strName.Append(_strSegmentIndex);
									spAlias->SetAlias(strName);
								}
								bAction = CreateVentShrinkeage();
							}

						}
					}
				}

				if (bAction && NULL_var != _spSipeSet)
				{
					GetFeaturesInGS(_spSipeSet, _spListOfSipes);
					if (_spListOfSipes.Size() > 0)
					{
						AssemblePlanes(_spListOfSipes, _spSipesAssembled);
						if (NULL_var != _spOGSShrinkageSet && NULL_var != _spSipesAssembled)
						{
							CATIAlias_var spAlias = _spSipesAssembled;
							if (NULL_var != spAlias)
							{
								CATUnicodeString strName = "SipesAssembled_";
								strName.Append(_strSegmentIndex);
								spAlias->SetAlias(strName);
							}
							bAction = CreateSipeShrinkeage();
						}
					}
				}
				/*else
				{
					if (NULL_var != _spOGSShrinkageSet && NULL_var != _spTargetSurface)
					{
						MRFGenericUtils::UpdateFeature(_spTargetSurface, _spOGSShrinkageSet, TRUE);
					}
				}*/
			}
			
		}
	}
	if (bAction)
		RequestDelayedDestruction();
}

//-------------------------------------------------------------------------
// ActionClose ()
//-------------------------------------------------------------------------
void MRFShrinkeageCmd::ActionClose(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	this->ExecuteUndoAtEnd();
	RequestDelayedDestruction();

	return;
}

//-------------------------------------------------------------------------
// OnObjectSelection ()
//-------------------------------------------------------------------------
CATBoolean MRFShrinkeageCmd::OnSelectorListSelected(void * iUsefulData)
{
	char * pstrAction = (char *)(CATCommandClientData)iUsefulData;
	CATString strAction(pstrAction);

	CATDialogAgent * pDialoAgent = NULL;
	CATPathElement * pPathElement = NULL;
	CATDlgSelectorList * pDlgSelector = NULL;

	if (!!_pMRFShrinkeageDlg)
	{
		_pMRFShrinkeageDlg->ClearAllSelections();

		if (strAction == "RefSurface")
		{
			pDialoAgent = _pRefSurfaceDialogAgent;
			pPathElement = _pRefSurfacePathElement;
			pDlgSelector = _pMRFShrinkeageDlg->GetRefSurfaceSelector();
		}
		else if (strAction == "Segment")
		{
			pDialoAgent = _pSegmentDialogAgent;
			pPathElement = _pSegmentPathElement;
			pDlgSelector = _pMRFShrinkeageDlg->GetSegmentSelector();
		}
		else if (strAction == "VentSet")
		{
			pDialoAgent = _pVentGeomSetDialogAgent;
			pPathElement = _pVentGeomSetPathElement;
			pDlgSelector = _pMRFShrinkeageDlg->GetVentGeomSetSelector();
		}
		else if (strAction == "SipeSet")
		{
			pDialoAgent = _pSipeSetDialogAgent;
			pPathElement = _pSipeSetPathElement;
			pDlgSelector = _pMRFShrinkeageDlg->GetSipeGeomSetSelector();
		}

		if (NULL != pDlgSelector)
			_pMRFShrinkeageDlg->SetFocusOnSelectorList(pDlgSelector);

		if (NULL != _pHSO)
		{
			_pHSO->Empty();
			if (NULL != pPathElement && 0 == _pHSO->IsMember(pPathElement))
				_pHSO->AddElement(pPathElement);
		}

		if (!!pDialoAgent)
			pDialoAgent->InitializeAcquisition();
	}

	return CATTrue;
}

//-------------------------------------------------------------------------
// OnObjectSelection ()
//-------------------------------------------------------------------------
CATBoolean MRFShrinkeageCmd::OnObjectSelection(void * iUsefulData)
{
	char * pstrAction = (char *)(CATCommandClientData)iUsefulData;
	CATString strAction(pstrAction);

	CATPathElementAgent * pPathElementAgent = NULL;
	CATPathElement * pPathElement = NULL;

	CATDlgSelectorList * pDlgSelector = NULL;
	CATDlgSelectorList * pNextDlgSelector = NULL;

	if (!!_pMRFShrinkeageDlg)
	{
		_pMRFShrinkeageDlg->ClearAllSelections();

		if (strAction == "RefSurface")
		{
			pPathElementAgent = _pRefSurfacePathElementAgent;
			pDlgSelector = _pMRFShrinkeageDlg->GetRefSurfaceSelector();
			pNextDlgSelector = _pMRFShrinkeageDlg->GetSegmentSelector();
		}
		else if (strAction == "Segment")
		{
			pPathElementAgent = _pSegmentPathElementAgent;
			pDlgSelector = _pMRFShrinkeageDlg->GetSegmentSelector();
			pNextDlgSelector = _pMRFShrinkeageDlg->GetVentGeomSetSelector();
		}
		else if (strAction == "VentSet")
		{
			pPathElementAgent = _pVentGeomSetPathElementAgent;
			pDlgSelector = _pMRFShrinkeageDlg->GetVentGeomSetSelector();
			pNextDlgSelector = _pMRFShrinkeageDlg->GetSipeGeomSetSelector();
		}
		else if (strAction == "SipeSet")
		{
			pPathElementAgent = _pSipeSetPathElementAgent;
			pDlgSelector = _pMRFShrinkeageDlg->GetSipeGeomSetSelector();
			pNextDlgSelector = pDlgSelector;
		}

		if (NULL != pDlgSelector && NULL != pNextDlgSelector)
		{ 
			_pMRFShrinkeageDlg->SetFocusOnSelectorList(pDlgSelector);

			if (!!pPathElementAgent)
			{
				pPathElement = pPathElementAgent->GetValue();
				if (NULL != pPathElement)
				{
					CATBaseUnknown_var spSelectedElement = pPathElement->CurrentElement();
					if (NULL_var != spSelectedElement)
					{
						if (strAction == "RefSurface")
						{
							if (IsValidReferenceSurface(spSelectedElement))
							{
								_pRefSurfacePathElement = pPathElement;
								_spRefSurface = spSelectedElement;
							}
							else
							{
								return CATFalse;
							}

						}
						else if (strAction == "Segment")
						{
							_pSegmentPathElement = pPathElement;
							_spSegment = spSelectedElement;
						}
						else if (strAction == "VentSet")
						{
							_pVentGeomSetPathElement = pPathElement;
							_spVentGeomSet = spSelectedElement;
						}
						else if (strAction == "SipeSet")
						{
							_pSipeSetPathElement = pPathElement;
							_spSipeSet = spSelectedElement;
						}

						CATUnicodeString strAlias = "";
						CATIAlias_var spAlias = spSelectedElement;
						if (NULL_var != spAlias)
						{
							strAlias = spAlias->GetAlias();
						}

						/*if (strAction == "RefSurface")
						{
							UpdateSegmentIndexFromRefSurface(strAlias);
						}*/
						if (strAction == "Segment")
						{
							UpdateSegmentIndexFromRefSurface(strAlias);
						}
						pDlgSelector->ClearLine();
						pDlgSelector->SetLine(strAlias);
						_pMRFShrinkeageDlg->SetFocusOnSelectorList(pNextDlgSelector);
					}
					if (NULL != _pHSO)
					{
						_pHSO->Empty();
						if (0 == _pHSO->IsMember(pPathElement))
							_pHSO->AddElement(pPathElement);
					}
				}
				pPathElementAgent->InitializeAcquisition();
			}
		}
	}
	return CATTrue;
}

