// Creates shrinkeage of the given element to deform
CATBoolean MRFShrinkeageCmd::CreateShrinkeage(CATIMmiMechanicalFeature_var ispElementToDeform, CATUnicodeString iElementName, CATIMmiMechanicalFeature_var & ospShrinkedElement)
{
	CATBoolean bShirnkeage = CATFalse;
	if (NULL_var != _spRefSurface && NULL_var != _spTargetSurface && NULL_var != _spGSMFactory && NULL_var != ispElementToDeform)
	{
		CreateWrapSurface(ispElementToDeform, ospShrinkedElement);
		if (NULL_var != ospShrinkedElement)
		{
			CATIAlias_var spAlias = ospShrinkedElement;
			if (NULL_var != spAlias)
			{
				CATUnicodeString strName = iElementName;
				strName.Append("_");
				strName.Append(_strSegmentIndex);
				strName.Append("_WrapSurface");
				spAlias->SetAlias(strName);
			}

			if (NULL_var != _spOGSShrinkageSet)
			{
				MRFGenericUtils::UpdateFeature(ospShrinkedElement, _spOGSShrinkageSet, TRUE);
				CATIMmiUsePrtPart_var spPrt = _spMechanicalPart;
				if (NULL_var != spPrt)
				{
					spPrt->SetInWorkObject(ospShrinkedElement);
				}
			}
			bShirnkeage = CATTrue;
		}
	}
	return bShirnkeage;
}

